#include <bits/stdc++.h>
using namespace std;
int t,n,m;
int main(){
    scanf("%d",&t);
    while(t--){
        scanf("%d%d",&n,&m);
        int s1=m/n,s2=m/n+(m%n>0);
        if(2*s1>s2 || s2*(n-1)+s1==m)
            cout<<"Yes\n";
        else
            cout<<"No\n";
    }
    return 0;
}
